const UserList = ({ onSelect }) => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setLoading(true);
    fetch('https://api.example.com/users')
      .then(r => r.json())
      .then(data => {
        setUsers(data);
        setLoading(false);
      });
  }, []);

  return (
    <FlatList
      data={users}
      renderItem={({ item }) => (
        <TouchableOpacity onPress={() => onSelect(item)} style={{ padding: 10, backgroundColor: '#FFFFFF' }}>
          <Text style={{ fontSize: 16, color: '#333333' }}>{item.name}</Text>
        </TouchableOpacity>
      )}
    />
  );
};
